<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    overflow: hidden;
    font-family: 'Ubuntu', 'Segoe UI', Arial, sans-serif;
    user-select: none;
  }

  #desktop {
    width: 100vw;
    height: 100vh;
    background: linear-gradient(135deg, #1a2a6c, #b21f1f, #fdbb2d);
    position: relative;
    overflow: hidden;
  }

  /* Desktop wallpaper overlay */
  #desktop::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    background:
      radial-gradient(ellipse at 20% 50%, rgba(26,42,108,0.7) 0%, transparent 60%),
      radial-gradient(ellipse at 80% 30%, rgba(178,31,31,0.5) 0%, transparent 50%),
      radial-gradient(ellipse at 50% 80%, rgba(253,187,45,0.3) 0%, transparent 60%);
    z-index: 0;
  }

  /* Desktop icons area */
  #desktop-icons {
    position: absolute;
    top: 10px;
    left: 10px;
    display: flex;
    flex-direction: column;
    gap: 20px;
    z-index: 1;
  }

  .desktop-icon {
    width: 80px;
    text-align: center;
    cursor: pointer;
    padding: 5px;
    border-radius: 4px;
    transition: background 0.2s;
  }

  .desktop-icon:hover {
    background: rgba(255,255,255,0.1);
  }

  .desktop-icon .icon-img {
    width: 48px;
    height: 48px;
    margin: 0 auto 5px;
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 28px;
    color: white;
  }

  .desktop-icon .icon-label {
    color: white;
    font-size: 13px;
    text-shadow: 0 1px 3px rgba(0,0,0,0.8);
  }

  /* Taskbar */
  #taskbar {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 48px;
    background: rgba(35, 39, 46, 0.97);
    backdrop-filter: blur(12px);
    display: flex;
    align-items: center;
    padding: 0 12px;
    z-index: 1000;
    border-top: 1px solid rgba(255,255,255,0.08);
  }

  #taskbar .start-btn {
    width: 36px;
    height: 36px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 4px;
    cursor: pointer;
    transition: background 0.2s;
    margin-right: 12px;
  }

  #taskbar .start-btn:hover {
    background: rgba(255,255,255,0.1);
  }

  #taskbar .start-btn svg {
    width: 24px;
    height: 24px;
  }

  /* Launcher buttons */
  #open-files, #open-notepad {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 6px 14px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 13px;
    color: white;
    transition: background 0.2s, transform 0.15s;
    margin-right: 8px;
    min-width: 140px;
  }

  #open-files:hover, #open-notepad:hover {
    background: rgba(255,255,255,0.1);
  }

  #open-files:active, #open-notepad:active {
    transform: scale(0.96);
  }

  #open-files .launcher-icon, #open-notepad .launcher-icon {
    width: 24px;
    height: 24px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 16px;
  }

  #open-files .launcher-icon { background: rgba(253,187,45,0.3); }
  #open-notepad .launcher-icon { background: rgba(255,193,7,0.3); }

  /* Taskbar app indicators */
  #taskbar .app-indicator {
    width: 3px;
    height: 24px;
    border-radius: 2px;
    margin-right: 8px;
    transition: background 0.2s;
  }

  /* Window chrome */
  .window {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -60%);
    width: 700px;
    min-width: 360px;
    height: 480px;
    min-height: 240px;
    background: #2d3139;
    border-radius: 10px;
    box-shadow: 0 16px 48px rgba(0,0,0,0.5), 0 4px 16px rgba(0,0,0,0.3);
    display: none;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
    border: 1px solid rgba(255,255,255,0.06);
  }

  .window.active {
    display: flex;
    z-index: 200;
  }

  /* Window title bar */
  .win-titlebar {
    height: 38px;
    background: rgba(45,49,57,0.95);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    cursor: default;
    border-bottom: 1px solid rgba(255,255,255,0.04);
    -webkit-app-region: drag;
  }

  .win-title {
    color: #cdd6f7;
    font-size: 13px;
    flex: 1;
    text-align: center;
    pointer-events: none;
  }

  .win-controls {
    display: flex;
    gap: 8px;
    -webkit-app-region: no-drag;
  }

  .win-close {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background: transparent;
    border: none;
    color: #cdd6f7;
    font-size: 14px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.2s;
  }

  .win-close:hover {
    background: #e76c53;
    color: white;
  }

  /* Files window */
  #files-window {
    width: 680px;
    height: 460px;
  }

  #files-toolbar {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 10px 16px;
    background: rgba(35,39,46,0.8);
    border-bottom: 1px solid rgba(255,255,255,0.04);
  }

  #files-up {
    padding: 6px 14px;
    background: transparent;
    border: none;
    color: #cdd6f7;
    font-size: 13px;
    cursor: pointer;
    border-radius: 4px;
    transition: background 0.2s;
  }

  #files-up:hover {
    background: rgba(255,255,255,0.08);
  }

  #files-path {
    color: #a9b1d6;
    font-size: 13px;
    flex: 1;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  #files-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
  }

  .fs-item {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 10px 14px;
    border-radius: 6px;
    cursor: pointer;
    transition: background 0.15s;
    color: #cdd6f7;
    font-size: 14px;
  }

  .fs-item:hover {
    background: rgba(255,255,255,0.08);
  }

  .fs-item .fs-icon {
    width: 36px;
    height: 36px;
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 20px;
    flex-shrink: 0;
  }

  .fs-item .fs-name {
    flex: 1;
  }

  /* Notepad window */
  #notepad-window {
    width: 720px;
    height: 500px;
  }

  #tabs {
    display: flex;
    align-items: center;
    background: rgba(35,39,46,0.8);
    border-bottom: 1px solid rgba(255,255,255,0.04);
    padding: 4px 8px;
    gap: 4px;
    overflow-x: auto;
    -webkit-app-region: no-drag;
  }

  .tab {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 5px 14px;
    border-radius: 6px;
    background: transparent;
    color: #a9b1d6;
    font-size: 13px;
    cursor: pointer;
    white-space: nowrap;
    transition: all 0.2s;
    max-width: 180px;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .tab:hover {
    background: rgba(255,255,255,0.06);
    color: #cdd6f7;
  }

  .tab.active {
    background: #3e4451;
    color: white;
  }

  .tab .tab-close {
    width: 18px;
    height: 18px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 12px;
    opacity: 0.6;
    transition: all 0.2s;
    cursor: pointer;
  }

  .tab .tab-close:hover {
    background: #e76c53;
    opacity: 1;
  }

  #new-tab-btn {
    padding: 4px 12px;
    border-radius: 6px;
    background: transparent;
    color: #a9b1d6;
    font-size: 13px;
    cursor: pointer;
    transition: all 0.2s;
    border: none;
    white-space: nowrap;
  }

  #new-tab-btn:hover {
    background: rgba(255,255,255,0.08);
    color: #cdd6f7;
  }

  #editor-container {
    flex: 1;
    position: relative;
  }

  #editor {
    width: 100%;
    height: 100%;
    background: #2d3139;
    color: #cdd6f7;
    border: none;
    outline: none;
    resize: none;
    padding: 16px;
    font-family: 'Ubuntu Mono', 'Cascadia Code', 'Fira Code', monospace;
    font-size: 14px;
    line-height: 1.6;
  }

  /* Scrollbar styling */
  ::-webkit-scrollbar { width: 8px; height: 8px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.15); border-radius: 4px; }
  ::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.25); }

  /* Filesystem icons */
  .icon-folder { background: linear-gradient(135deg, #e76c53, #d4a853); color: white; }
  .icon-file { background: rgba(255,255,255,0.1); color: #cdd6f7; }

  /* Dragging window */
  .window.dragging {
    cursor: move;
    opacity: 0.9;
  }
</style>
</head>
<body>

<div id="desktop">
  <!-- Desktop icons -->
  <div id="desktop-icons">
    <div class="desktop-icon" data-app="files">
      <div class="icon-img" style="background: linear-gradient(135deg, #e76c53, #d4a853);">📁</div>
      <div class="icon-label">Files</div>
    </div>
    <div class="desktop-icon" data-app="notepad">
      <div class="icon-img" style="background: linear-gradient(135deg, #f0c674, #e8a838);">📝</div>
      <div class="icon-label">Notepad</div>
    </div>
  </div>

  <!-- Taskbar -->
  <div id="taskbar">
    <div class="start-btn" title="Start Menu">
      <svg viewBox="0 0 24 24" fill="#e76c53"><path d="M3 12l9-9v9H3V12zm0 2l9 9V13H3v11zm18-11h-9v9h9V3z"/></svg>
    </div>

    <div id="open-files" class="launcher-btn">
      <div class="launcher-icon">📁</div>
      <span>Files</span>
    </div>
    <div id="open-notepad" class="launcher-btn">
