</div>

<script>
(function() {
  'use strict';

  // ─── Utility: generate unique IDs ───
  let _idCounter = 0;
  function uid(prefix) { return prefix + (++_idCounter); }

  // ─── Filesystem data (static fake data) ───
  const FS = {
    '/': [
      { name: 'bin', type: 'folder' },
      { name: 'etc', type: 'folder' },
      { name: 'home', type: 'folder' },
      { name: 'usr', type: 'folder' },
      { name: 'var', type: 'folder' }
    ],
    '/bin': [
      { name: 'bash', type: 'file' },
      { name: 'ls', type: 'file' },
      { name: 'cp', type: 'file' },
      { name: 'mv', type: 'file' },
      { name: 'rm', type: 'file' }
    ],
    '/etc': [
      { name: 'passwd', type: 'file' },
      { name: 'hosts', type: 'file' },
      { name: 'ssh_config', type: 'file' },
      { name: 'systemd', type: 'folder' }
    ],
    '/etc/systemd': [
      { name: 'network.conf', type: 'file' },
      { name: 'services.conf', type: 'file' }
    ],
    '/home': [
      { name: 'user', type: 'folder' }
    ],
    '/home/user': [
      { name: 'Documents', type: 'folder' },
      { name: 'Downloads', type: 'folder' },
      { name: 'Pictures', type: 'folder' },
      { name: 'readme.txt', type: 'file' }
    ],
    '/home/user/Documents': [
      { name: 'notes.md', type: 'file' },
      { name: 'todo.txt', type: 'file' },
      { name: 'projects', type: 'folder' }
    ],
    '/home/user/Documents/projects': [
      { name: 'desktop-env.html', type: 'file' },
      { name: 'config.json', type: 'file' }
    ],
    '/home/user/Downloads': [
      { name: 'ubuntu-logo.png', type: 'file' },
      { name: 'manual.pdf', type: 'file' }
    ],
    '/home/user/Pictures': [
      { name: 'screenshot.jpg', type: 'file' },
      { name: 'wallpaper.png', type: 'file' }
    ],
    '/usr': [
      { name: 'bin', type: 'folder' },
      { name: 'lib', type: 'folder' },
      { name: 'share', type: 'folder' }
    ],
    '/usr/bin': [
      { name: 'python3', type: 'file' },
      { name: 'node', type: 'file' },
      { name: 'git', type: 'file' },
      { name: 'npm', type: 'file' }
    ],
    '/usr/lib': [
      { name: 'libc.so.6', type: 'file' },
      { name: 'libssl.so.3', type: 'file' }
    ],
    '/usr/share': [
      { name: 'man', type: 'folder' },
      { name: 'icons', type: 'folder' }
    ],
    '/var': [
      { name: 'log', type: 'folder' },
      { name: 'cache', type: 'folder' },
      { name: 'tmp', type: 'folder' }
    ],
    '/var/log': [
      { name: 'syslog', type: 'file' },
      { name: 'auth.log', type: 'file' }
    ],
    '/var/cache': [
      { name: 'apt', type: 'folder' },
      { name: 'dpkg', type: 'folder' }
    ]
  };

  // ─── Filesystem navigation state ───
  let currentPath = '/';

  function getEntries(path) {
    return FS[path] || [];
  }

  function getParentPath(path) {
    if (path === '/') return path;
    const idx = path.lastIndexOf('/');
    return idx > 0 ? path.substring(0, idx) : '/';
  }

  // ─── Files window rendering ───
  const filesListEl = document.getElementById('files-list');
  const filesPathEl = document.getElementById('files-path');
  const filesUpBtn = document.getElementById('files-up');

  function renderFiles() {
    const entries = getEntries(currentPath);
    filesListEl.innerHTML = '';

    if (entries.length === 0) {
      const empty = document.createElement('div');
      empty.className = 'fs-item';
      empty.style.color = '#6b7280';
      empty.textContent = '(empty directory)';
      filesListEl.appendChild(empty);
      return;
    }

    entries.forEach(entry => {
      const item = document.createElement('div');
      item.className = 'fs-item';
      item.dataset.path = currentPath + '/' + entry.name;

      const icon = document.createElement('div');
      icon.className = 'fs-icon' + (entry.type === 'folder' ? ' icon-folder' : ' icon-file');
      icon.textContent = entry.type === 'folder' ? '📁' : '📄';

      const name = document.createElement('span');
      name.className = 'fs-name';
      name.textContent = entry.name;

      item.appendChild(icon);
      item.appendChild(name);

      // Double-click to navigate into folder
      if (entry.type === 'folder') {
        item.addEventListener('dblclick', () => {
          currentPath = item.dataset.path;
          renderFiles();
        });
      }

      filesListEl.appendChild(item);
    });
  }

  function updatePathDisplay() {
    filesPathEl.textContent = currentPath;
  }

  // ─── Files window open/close ───
  const filesWindow = document.getElementById('files-window');
  let filesDragState = null;

  function openFiles() {
    if (filesWindow.classList.contains('active')) return;
    currentPath = '/';
    renderFiles();
    updatePathDisplay();
    filesWindow.classList.add('active');
    setActiveIndicator('files');
  }

  function closeFiles() {
    filesWindow.classList.remove('active');
    setActiveIndicator('files', false);
  }

  // ─── Notepad window open/close ───
  const notepadWindow = document.getElementById('notepad-window');
  let notepadDragState = null;

  function openNotepad() {
    if (notepadWindow.classList.contains('active')) return;
    loadNotepadTabs();
    notepadWindow.classList.add('active');
    setActiveIndicator('notepad');
  }

  function closeNotepad() {
    notepadWindow.classList.remove('active');
    setActiveIndicator('notepad', false);
  }

  // ─── Notepad tabs persistence ───
  const TABS_KEY = 'ubuntu_notepad_tabs';

  function loadNotepadTabs() {
    try {
      const data = JSON.parse(localStorage.getItem(TABS_KEY));
      if (data && Array.isArray(data) && data.length > 0) {
        renderTabStrip(data);
        activateTab(0, data[0].name);
        return;
      }
    } catch(e) {}

    // Default: one empty tab
    const defaultData = [{ name: 'untitled', content: '' }];
    saveNotepadTabs(defaultData);
    renderTabStrip(defaultData);
    activateTab(0, 'untitled');
  }

  function saveNotepadTabs(tabs) {
    localStorage.setItem(TABS_KEY, JSON.stringify(tabs));
  }

  function createTabElement(tabName, isActive) {
    const tab = document.createElement('div');
    tab.className = 'tab' + (isActive ? ' active' : '');
    tab.dataset.tabId = tabName;

    const closeBtn = document.createElement('span');
    closeBtn.className = 'tab-close';
    closeBtn.textContent = '✕';
    closeBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      removeTab(tabName);
    });

    tab.appendChild(closeBtn);
    const label = document.createElement('span');
    label.textContent = tabName;
    tab.appendChild(label);

    return tab;
  }

  function renderTabStrip(tabs) {
    const tabsEl = document.getElementById('tabs');
    tabsEl.innerHTML = '';

    tabs.forEach((tab, idx) => {
      const isActive = (idx === activeTabIndex);
      const el = createTabElement(tab.name, isActive);
      el.addEventListener('click', () => activateTab(idx));
      tabsEl.appendChild(el);
    });

    // Add new tab button
    const newBtn = document.createElement('button');
    newBtn.id = 'new-tab-btn';
    newBtn.textContent = '+ New Tab';
    newBtn.addEventListener('click', createNewTab);
    tabsEl.appendChild(newBtn);
  }

  let activeTabIndex = 0;

  function activateTab(idx) {
    const tabs = getNotepadTabs();
    if (idx < 0 || idx >= tabs.length) return;

    // Update tab classes
    document.querySelectorAll('.tab').forEach((t, i) => {
      t.classList.toggle('active', i === idx);
    });

    activeTabIndex = idx;
    const editor = document.getElementById('editor');
    editor.value = tabs[idx].content;
  }

  function getNotepadTabs() {
    try { return JSON.parse(localStorage.getItem(TABS_KEY)); } catch(e) { return []; }
  }

  function createNewTab() {
    const tabs = getNotepadTabs();
    const name = 'untitled-' + (tabs.length + 1);
    tabs.push({ name: name, content: '' });
    saveNotepadTabs(tabs);
    renderTabStrip(tabs);
    activateTab(tabs.length - 1);
  }

  function removeTab(tabName) {
    const tabs = getNotepadTabs();
    const idx = tabs.findIndex(t => t.name === tabName);
    if (idx < 0) return;

    tabs.splice(idx, 1);
    saveNotepadTabs(tabs);

    // If we removed the active tab, switch to another or create new one
    if (tabs.length > 0) {
      const newIndex = Math.min(activeTabIndex, tabs.length - 1);
      renderTabStrip(tabs);
      activateTab(newIndex);
    } else {
      // All closed — show a default tab
      saveNotepadTabs([{ name: 'untitled', content: '' }]);
      renderTabStrip([{ name: 'untitled', content: '' }]);
      activeTabIndex = 0;
      activateTab(0);
    }
  }

  // ─── Notepad window close button ───
  document.querySelector('#notepad-window .win-close').addEventListener('click', closeNotepad);

  // ─── Files window close button ───
  document.querySelector('#files-window .win-close').addEventListener('click', closeFiles);

  // ─── Launcher buttons ───
  document.getElementById('open-files').addEventListener('click', openFiles);
  document.getElementById('open-notepad').addEventListener('click', openNotepad);

  // ─── Files up button ───
  filesUpBtn.addEventListener('click', () => {
    const parent = getParentPath(currentPath);
    if (parent !== currentPath) {
      currentPath = parent;
      renderFiles();
      updatePathDisplay();
    }
  });

  // ─── Window dragging ───
  function makeDraggable(windowEl, stateKey) {
    let isDragging = false;
    let startX, startY, startLeft, startTop;

    const titlebar = windowEl.querySelector('.win-titlebar');

    titlebar.addEventListener('mousedown', (e) => {
      if (e.target.classList.contains('win-close')) return;
      isDragging = true;
      stateKey.current = true;
      startX = e.clientX;
      startY = e.clientY;
      const rect = windowEl.getBoundingClientRect();
      startLeft = rect.left;
      startTop = rect.top;
      windowEl.classList.add('dragging');
    });

    document.addEventListener('mousemove', (e) => {
      if (!isDragging) return;
      const dx = e.clientX - startX;
      const dy = e.clientY - startY;
      windowEl.style.left = (startLeft + dx) + 'px';
      windowEl.style.top = (startTop + dy) + 'px';
      windowEl.style.transform = 'none';
    });

    document.addEventListener('mouseup', () => {
      isDragging = false;
      stateKey.current = false;
      windowEl.classList.remove('dragging');
    });
  }

  makeDraggable(filesWindow, filesDragState);
  makeDraggable(notepadWindow, notepadDragState);

  // ─── Active indicator toggling ───
  function setActiveIndicator(appName, show) {
    const el = document.getElementById(appName + '-indicator');
    if (show !== undefined) {
      el.style.display = show ? 'block' : 'none';
    } else {
      el.style.display = window.getComputedStyle(el).display === 'none' ? 'block' : 'none';
    }
  }

  // ─── Keyboard shortcuts ───
  document.addEventListener('keydown', (e) => {
    if (e.target.tagName === 'TEXTAREA') return;

    if ((e.ctrlKey || e.metaKey) && e.key === 'n') {
      e.preventDefault();
      createNewTab();
    }
  });

  // ─── Initial render ───
  renderFiles();
  updatePathDisplay();
})();
